import { test, expect } from './fixtures';

test('homepage loads', async ({ page }) => {
  await page.goto('https://myapp.com/');
  await expect(page.getByText('Welcome')).toBeVisible();
});
```

### 5. Graba — ejecuta una vez contra la API real

```bash
# In fixtures.ts: const MODE = 'record' as const;
npx playwright test
# .har files are written to e2e/recordings/ automatically
```

### 6. Cambia a reproducción y haz commit

```bash
# In fixtures.ts: const MODE = 'replay' as const;
git add e2e/recordings/
git commit -m "add e2e recordings"
```

CI ahora se ejecuta sin ningún acceso a la red.

:::caution
**No** añadas `e2e/recordings` a `.gitignore`. Las grabaciones deben estar en git para la reproducción en CI.
:::

Añade esto a `.gitattributes` para colapsar archivos de grabación grandes en los diffs de PR:

```text
/e2e/recordings/** binary
```

Para cualquier cosa más allá de un par de flags — especialmente las regex de redacción de cuerpo — pon las opciones en un archivo de configuración. El proxy autodetecta `test-proxy-recorder.config.{ts,js,mjs,cjs}` en el directorio actual, o pasa `--config <path>` para apuntar a uno explícitamente. Los archivos `.ts` funcionan sin más.

```ts
// test-proxy-recorder.config.ts
import { defineConfig } from 'test-proxy-recorder';

export default defineConfig({
  target: 'http://localhost:3002',
  port: 8100,
  recordingsDir: './e2e/recordings',
  timeout: 120_000,
  // Redaction is on by default; this object customizes it (use `redaction: false` to disable).
  redaction: {
    headers: ['x-api-key'],         // extra headers, merged with the defaults
    bodyPatterns: [/sk_live_\w+/g], // real RegExp literals — no CLI escaping
    allowCookies: ['theme'],        // keep these cookies unredacted
  },
  websocket: {
    timing: 'burst',                // 'burst' (default) or 'original' (re-paced)
  },
});
```

```bash
test-proxy-recorder                 # all options from the config file
test-proxy-recorder --port 9000     # config file, but CLI port wins
```

## Precedencia

Cada opción se resuelve como **flag de CLI → archivo de configuración → valor por defecto integrado**. Un flag que pasas en la línea de comandos siempre anula el archivo de configuración; lo que omitas recurre a la configuración, y luego al valor por defecto. (Los flags de lista como `--redact-headers` *reemplazan* la lista de la configuración en lugar de fusionarla — pásalo solo cuando quieras anular.) `target` puede darse como argumento de la CLI o como `target` en la configuración; el argumento gana cuando ambos están presentes.

Mira la [referencia de la API](/docs/reference/api/interfaces/config/) para el tipo `Config` completo.

Los frameworks SSR como Next.js hacen llamadas `fetch` del lado del servidor que pasan por el proxy sin un contexto de navegador. El proxy identifica a qué sesión pertenecen esas peticiones mediante la cabecera `x-test-rcrd-id` — la misma cabecera que `playwrightProxy.before()` establece en la `page` del navegador. Esta cabecera **solo es necesaria para SSR** — para pruebas solo de navegador el proxy recurre automáticamente a la sesión establecida globalmente.

Para que las peticiones SSR lleven esta cabecera, usa una de las siguientes opciones.

## Middleware (recomendado)

Next.js 16 usa `proxy.ts` como punto de entrada del middleware (con la función exportada llamada `proxy`). Colócalo en la raíz del proyecto junto a `next.config.ts`:

```typescript
// proxy.ts  (Next.js 16 middleware convention)
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';
import { setNextProxyHeaders } from 'test-proxy-recorder/nextjs';

export function proxy(request: NextRequest) {
  const response = NextResponse.next();
  setNextProxyHeaders(request, response); // no-op in production
  return response;
}

export const config = {
  matcher: ['/((?!_next/static|_next/image|favicon.ico).*)'],
};
```

:::note[Next.js 15 y anteriores]
El punto de entrada es `middleware.ts` con la función llamada `middleware` — todo lo demás es idéntico:

```typescript
// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';
import { setNextProxyHeaders } from 'test-proxy-recorder/nextjs';

export function middleware(request: NextRequest) {
  const response = NextResponse.next();
  setNextProxyHeaders(request, response); // no-op in production
  return response;
}
```
:::

